  "type": "QUIZ",
  "title": "Core Concepts of Java Basics Quiz",
  "lessonText": "Test your understanding of Java control structures.",
  "data": {
    "questions": [
      {
        "question": "What is the purpose of an if statement in Java?",
        "options": [
          "To execute a block of code based on a condition.",
          "To loop through a set of instructions.",
          "To declare a variable.",
          "To handle exceptions."
        ],
        "correctAnswer": 0,
        "explanation": "If statements are used to execute a block of code based on a condition."
      },
      {
        "question": "In the context of control structures, what does an else statement do?",
        "options": [
          "It executes a block of code if the condition is false.",
          "It creates a new variable.",
          "It ends the program.",
          "It loops through code."
        ],
        "correctAnswer": 0,
        "explanation": "An else statement executes a block of code if the condition in the if statement is false."
      },
      {
        "question": "Which of the following is a valid if-else statement in Java?",
        "options": [
          "if (condition) { System.out.println('True'); } else { System.out.println('False'); }",
          "if condition { System.out.println('True'); } else { System.out.println('False'); }",
          "if (condition) System.out.println('True'); else System.out.println('False');",
          "if (condition) { System.out.println('True'); else { System.out.println('False'); }"
        ],
        "correctAnswer": 0,
        "explanation": "The first option is a valid if-else statement in Java."
      },
      {
        "question": "What will the following code output? if (5 > 3) { System.out.println('A'); } else { System.out.println('B'); }",
        "options": [
          "A",
          "B",
          "Error",
          "Nothing"
        ],
        "correctAnswer": 0,
        "explanation": "The condition 5 > 3 is true, so 'A' will be printed."
      }
    ]
  }
}
